import{_ as o,o as t,c as d,ak as s}from"./chunks/framework.oFDsBAuP.js";const p=JSON.parse('{"title":"模型列表","description":"列出与发现模型：OpenAI / Gemini 列表及单模型查询说明（含右侧多语言请求与响应示例）","frontmatter":{"title":"模型列表","description":"列出与发现模型：OpenAI / Gemini 列表及单模型查询说明（含右侧多语言请求与响应示例）","outline":false,"apiMethod":"GET","apiPath":"/v1/models"},"headers":[],"relativePath":"api/ai-model/models/index.md","filePath":"api/ai-model/models/index.md"}'),n={name:"api/ai-model/models/index.md"};function a(i,e,r,c,l,g){return t(),d("div",null,[...e[0]||(e[0]=[s('<h1 id="模型列表" tabindex="-1">模型列表 <a class="header-anchor" href="#模型列表" aria-label="Permalink to &quot;模型列表&quot;">​</a></h1><p>本组接口用于在调用对话、补全等能力之前，<strong>拉取当前账号可见的模型清单</strong>（及可选的单模型详情），并与控制台、模型广场中展示的可用范围相对应。</p><p>在 <strong>本页与 <a href="./list/listmodels.html">列出模型（OpenAI 格式）</a></strong> 的桌面视图下，右侧提供 <strong>多语言请求示例</strong>（cURL、Python、JavaScript、Go、PHP）与 <strong>JSON 响应样例</strong>（网关 Base URL 以文档示例 <code>minitoken.vip</code> 为准，请替换为你的部署地址）。</p><p>网关可能在同一路径上按请求头返回 <strong>OpenAI</strong>、<strong>Anthropic</strong> 或 <strong>Gemini</strong> 形态的列表；另提供 <strong>Gemini 原生</strong> 路径，便于已对接 Google API 形态的客户端直接使用。</p><h2 id="接口一览" tabindex="-1">接口一览 <a class="header-anchor" href="#接口一览" aria-label="Permalink to &quot;接口一览&quot;">​</a></h2><table tabindex="0"><thead><tr><th>文档</th><th>方法</th><th>路径</th><th>说明</th></tr></thead><tbody><tr><td><a href="./list/listmodels.html">列出模型（OpenAI 格式）</a></td><td><code>GET</code></td><td><code>/v1/models</code></td><td>响应字段、查询参数与常见 OpenAI 兼容实现一致方向的说明；正文含多厂商列表格式、错误与扩展字段说明。</td></tr><tr><td><a href="./list/listmodelsgemini.html">列出模型（Gemini 原生格式）</a></td><td><code>GET</code></td><td><code>/v1beta/models</code></td><td>返回与 Gemini REST 对齐的 <code>models</code> 数组。</td></tr><tr><td><a href="./get-model.html">获取模型</a></td><td><code>GET</code></td><td><code>/v1/models/{model}</code></td><td>若网关开放，用于查询单个模型详情；未开放时以列表接口为准。</td></tr></tbody></table><h2 id="响应-openai-列表形态" tabindex="-1">响应（OpenAI 列表形态） <a class="header-anchor" href="#响应-openai-列表形态" aria-label="Permalink to &quot;响应（OpenAI 列表形态）&quot;">​</a></h2><ul><li>顶层 <strong><code>object</code></strong> 在 OpenAI 兼容形态下为 <strong><code>list</code></strong>。</li><li>模型列表位于 <strong><code>data</code></strong> 数组中；每一项为一个 <strong>model</strong> 对象。</li></ul><p>每个模型在最小兼容场景下通常包含：</p><ul><li><strong><code>id</code></strong>（string）：模型标识符</li><li><strong><code>object</code></strong>（string）：<code>model</code></li><li><strong><code>created</code></strong>（integer）：创建时间戳</li><li><strong><code>owned_by</code></strong>（string）：模型提供方</li></ul><p>部分网关还会在条目上附带 <strong>扩展元数据</strong>（键名可能带服务商或网关约定前缀），例如与分类、定价、能力摘要相关的字段。更完整的「仅详情可见」元数据一般在 <strong><code>GET /v1/models/{model}</code></strong> 中；<strong><code>GET /v1/models</code></strong> 更侧重发现与列表。</p><h2 id="查询参数" tabindex="-1">查询参数 <a class="header-anchor" href="#查询参数" aria-label="Permalink to &quot;查询参数&quot;">​</a></h2><p>以下为部分实现中常见的 <strong>可选</strong> 能力（未实现的参数可能被网关忽略）：</p><ul><li><strong>公开分类筛选</strong>：如 <code>chat</code>、<code>image</code>、<code>video</code>、<code>audio</code>、<code>tts</code>、<code>stt</code>、<code>music</code>、<code>3d</code>、<code>embedding</code>、<code>rerank</code>、<code>translation</code> 等。</li><li><strong>非聊天推荐场景</strong>：如 <code>image</code>、<code>video</code>、<code>music</code>、<code>3d</code>、<code>tts</code>、<code>stt</code>、<code>embedding</code>、<code>rerank</code>、<code>translation</code> 等与 <code>recommended_for</code> 等参数配合（若支持）。</li><li><strong>提供方筛选</strong>：如 <code>openai</code>、<code>anthropic</code>、<code>google</code>、<code>deepseek</code> 等。</li><li><strong>模型标签</strong>：如 <code>chat</code>、<code>image</code>、<code>video</code>、<code>embedding</code>、<code>translation</code> 等。</li></ul><p>当存在 <code>recommended_for</code> 等推荐语义时，部分网关会按缓存的成功率快照对非聊天模型排序；样本不足的模型仍可能出现在列表中，但排序靠后。</p><p>在 <strong>New API 类网关</strong> 上，查询参数 <strong><code>key</code></strong> 还可能参与 <strong>Gemini 列表格式</strong> 的判定，与上表属于不同维度，可同时存在或仅实现其一。详见 <a href="./list/listmodels.html">列出模型（OpenAI 格式）</a> 正文。</p><h2 id="认证" tabindex="-1">认证 <a class="header-anchor" href="#认证" aria-label="Permalink to &quot;认证&quot;">​</a></h2><p>开放 API 统一使用控制台创建的令牌：</p><div class="language-http vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">http</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">Authorization</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">:</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> Bearer sk-xxxxxx</span></span></code></pre></div><p>将 <code>sk-xxxxxx</code> 替换为你的 <strong>API Key</strong>。勿把密钥写入公开仓库或前端明文配置。</p><h2 id="使用注意" tabindex="-1">使用注意 <a class="header-anchor" href="#使用注意" aria-label="Permalink to &quot;使用注意&quot;">​</a></h2><ul><li>实际返回的模型集合受 <strong>渠道、分组、计费与运营策略</strong> 影响，与右侧示例不一定完全一致。</li><li>对话补全、Responses、Claude Messages、<strong>Embedding</strong> 与 <strong>重排序</strong> 等见侧栏 <strong>文本</strong>；<strong>创建 / 编辑图像、变体</strong> 见侧栏 <strong>图像</strong>。TTS、转录、音频翻译等接口说明位于 <code>api/ai-model/audio/</code> 文档目录（侧栏入口暂不提供）。</li></ul>',22)])])}const m=o(n,[["render",a]]);export{p as __pageData,m as default};
